#include <NewPing.h>

// Ultrasonic Sensor Configuration
#define TRIGGER_PIN {{.triggerPin}}
#define ECHO_PIN {{.echoPin}}
#define MAX_DISTANCE {{.maxDistance}} // Maximum distance we want to ping for (in centimeters)
#define ALERT_THRESHOLD {{.alertThreshold}} // Alert threshold in cm
#define ALERT_LED_PIN {{.ledPin}} // LED pin for visual alerts
#define BUZZER_PIN {{.buzzerPin}} // Buzzer pin for audible alerts (0 = disabled)
#define READING_INTERVAL {{.readingInterval}} // Milliseconds between readings

// Create NewPing object
NewPing sonar(TRIGGER_PIN, ECHO_PIN, MAX_DISTANCE);

// Global variables
unsigned long last_reading_time = 0;
int last_distance = 0;
bool alert_active = false;
unsigned long alert_start_time = 0;
const unsigned long alert_duration = 5000; // Alert for 5 seconds
int consecutive_alerts = 0;
const int max_consecutive_alerts = 3; // Reduce false positives

// Function prototypes
int get_distance();
void handle_alert(int distance);
void reset_alert();
void beep(int duration_ms);

void setup() {
  Serial.begin(115200);
  Serial.println("Ultrasonic Distance Sensor with Alerts Starting...");

  // Initialize pins
  pinMode(ALERT_LED_PIN, OUTPUT);
  digitalWrite(ALERT_LED_PIN, LOW);

  if (BUZZER_PIN > 0) {
    pinMode(BUZZER_PIN, OUTPUT);
    digitalWrite(BUZZER_PIN, LOW);
  }

  // Wait for sensor to stabilize
  delay(1000);

  Serial.print("Configuration:");
  Serial.print(" Trigger Pin: ");
  Serial.print(TRIGGER_PIN);
  Serial.print(", Echo Pin: ");
  Serial.print(ECHO_PIN);
  Serial.print(", Max Distance: ");
  Serial.print(MAX_DISTANCE);
  Serial.print("cm, Alert Threshold: ");
  Serial.print(ALERT_THRESHOLD);
  Serial.println("cm");

  // Initial reading
  int initial_distance = get_distance();
  Serial.print("Initial distance: ");
  Serial.print(initial_distance);
  Serial.println("cm");
}

void loop() {
  unsigned long current_time = millis();

  // Take reading at specified interval
  if (current_time - last_reading_time >= READING_INTERVAL) {
    int distance = get_distance();
    last_reading_time = current_time;

    // Only process valid readings
    if (distance > 0 && distance <= MAX_DISTANCE) {
      last_distance = distance;

      // Check for alert condition
      if (distance <= ALERT_THRESHOLD) {
        consecutive_alerts++;
        handle_alert(distance);
      } else {
        consecutive_alerts = 0;
        reset_alert();
      }

      // Output to serial
      Serial.print("Distance: ");
      Serial.print(distance);
      Serial.print("cm");
      if (alert_active) {
        Serial.print(" [ALERT]");
      }
      Serial.println();
    }
  }

  // Handle alert timeout
  if (alert_active && (current_time - alert_start_time >= alert_duration)) {
    reset_alert();
  }

  delay(10); // Small delay to prevent overwhelming the sensor
}

int get_distance() {
  // Get distance in centimeters
  int distance = sonar.ping_cm();

  // NewPing returns 0 for no echo (out of range)
  if (distance == 0) {
    distance = MAX_DISTANCE; // Treat as maximum distance
  }

  return distance;
}

void handle_alert(int distance) {
  // Only trigger alert after consecutive readings to reduce false positives
  if (consecutive_alerts >= 2) {
    if (!alert_active) {
      // Start new alert
      alert_active = true;
      alert_start_time = millis();

      Serial.print("ALERT! Object detected at ");
      Serial.print(distance);
      Serial.println("cm");

      // Turn on LED
      digitalWrite(ALERT_LED_PIN, HIGH);

      // Sound buzzer if enabled
      if (BUZZER_PIN > 0) {
        beep(200); // Initial beep
      }
    } else {
      // Continue alert - periodic beeps
      if (BUZZER_PIN > 0) {
        unsigned long alert_elapsed = millis() - alert_start_time;
        if (alert_elapsed % 1000 < 200) { // Beep pattern: 200ms on, 800ms off
          digitalWrite(BUZZER_PIN, HIGH);
        } else {
          digitalWrite(BUZZER_PIN, LOW);
        }
      }
    }
  }
}

void reset_alert() {
  if (alert_active) {
    Serial.println("Alert cleared");
  }

  alert_active = false;
  digitalWrite(ALERT_LED_PIN, LOW);

  if (BUZZER_PIN > 0) {
    digitalWrite(BUZZER_PIN, LOW);
  }
}

void beep(int duration_ms) {
  if (BUZZER_PIN > 0) {
    digitalWrite(BUZZER_PIN, HIGH);
    delay(duration_ms);
    digitalWrite(BUZZER_PIN, LOW);
  }
}
